/**
 * Web Modal Component
 *
 */

import React from 'react'
import clsx from 'clsx'
import { extendExistingPropsWithContext } from '../../../shared/component-helper'
import Button from '../../button/Button'
import Context from '../../../shared/Context'
import type { ButtonProps } from '../../button/Button'

export type CloseButtonProps = {
  /**
   * The title of the close button. Defaults to `Close` or `Lukk`.
   */
  closeTitle?: string
} & Partial<ButtonProps>

function CloseButton(props: CloseButtonProps) {
  const context = React.useContext(Context)

  // use only the props from context, who are available here anyway
  const {
    closeTitle = null,
    size = 'default',
    iconPosition = 'left',
    className = null,
    ...buttonProps
  } = extendExistingPropsWithContext(
    props,
    {
      closeTitle: null,
      size: 'default',
      iconPosition: 'left',
      className: null,
    },
    context.getTranslation(props).Modal
  )

  return (
    <Button
      type="button"
      variant="tertiary"
      icon="close"
      text={closeTitle}
      size={size}
      iconPosition={iconPosition}
      className={clsx('dnb-modal__close-button', className)}
      {...buttonProps}
    />
  )
}

export default CloseButton
